[DataContractAttribute]
[SysOperationContractProcessing(classStr(UBSOutboundInterfaceVendInvoiceContractUIBuilder))]
internal final class UBSOutboundInterfaceVendInvoiceContract
{
    DataAreaId legalEntity;
    boolean reprocessError;

}

Method.Source:
/// <summary>
/// Legal entity for the export
/// </summary>
/// <param name = "_legalEntity">legalEntity</param>
/// <returns>legalEntity</returns>
[DataMemberAttribute]
public DataAreaId parmLegalEntity(DataAreaId _legalEntity = legalEntity)
{
    legalEntity = _legalEntity ;
    return legalEntity ;
}

/// <summary>
/// Include error records
/// </summary>
/// <param name = "_legalEntity">legalEntity</param>
/// <returns>legalEntity</returns>
[DataMemberAttribute,
    SysOperationLabelAttribute(literalStr("@UBS:UBSReprocessError"))]
public boolean parmReprocessError(boolean _reprocessError = reprocessError)
{
    reprocessError = _reprocessError ;
    return reprocessError ;
}
